#include <stdio.h>
#include <stdlib.h>
#define N 2000
int parent[N], rank[N];
int find(int x) { return parent[x] == x ? x : (parent[x] = find(parent[x])); }
void unionSet(int x, int y) { int rootX = find(x), rootY = find(y); if (rootX != rootY) { if (rank[rootX] > rank[rootY]) parent[rootY] = rootX; else { parent[rootX] = rootY; if (rank[rootX] == rank[rootY]) rank[rootY]++; } } }
int compare(const void *a, const void *b) { int *edgeA = *(int **)a, *edgeB = *(int **)b; return edgeA[2] - edgeB[2]; }
int main() {
    int n;
    scanf("%d", &n);
    int **edges = (int **)malloc(n * n * sizeof(int *));
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            edges[i * n + j] = (int *)malloc(3 * sizeof(int));
            edges[i * n + j][0] = i;
            edges[i * n + j][1] = j;
            scanf("%d", &edges[i * n + j][2]);
        }
    }
    qsort(edges, n * n, sizeof(int *), compare);
    for (int i = 0; i < n; i++) parent[i] = i, rank[i] = 0;
    int mstCost = 0, edgeCount = 0;
    for (int i = 0; i < n * n; i++) {
        int x = edges[i][0], y = edges[i][1], cost = edges[i][2];
        if (find(x) != find(y)) {
            unionSet(x, y);
            mstCost += cost;
            edgeCount++;
            if (edgeCount == n - 2) break;
        }
    }
    printf("%d\n", mstCost);
    return 0;
}

