# COMPLETE, RUNNABLE Python3 code
import sys
N = 2000
def find(x, parent):
    if parent[x] == x:
        return x
    parent[x] = find(parent[x], parent)
    return parent[x]
def unionSet(x, y, parent, rank):
    rootX = find(x, parent)
    rootY = find(y, parent)
    if rootX != rootY:
        if rank[rootX] > rank[rootY]:
            parent[rootY] = rootX
        else:
            parent[rootX] = rootY
            if rank[rootX] == rank[rootY]:
                rank[rootY] += 1
def main():
    input = sys.stdin.readline
    n = int(input())
    edges = []
    for i in range(n):
        for j in range(n):
            cost = int(input())
            edges.append((i, j, cost))
    edges.sort(key=lambda x: x[2])
    parent = list(range(n))
    rank = [0] * n
    mstCost = 0
    edgeCount = 0
    for x, y, cost in edges:
        if find(x, parent) != find(y, parent):
            unionSet(x, y, parent, rank)
            mstCost += cost
            edgeCount += 1
            if edgeCount == n - 2:
                break
    print(mstCost)
if __name__ == '__main__':
    main()

